function testProfiling() {
            var ans1 = document.querySelector('input[name="ans1"]:checked').value;
            var ans2 = document.querySelector('input[name="ans2"]:checked').value;
            var resultBox = document.getElementById('profilingResult');
            resultBox.style.display = 'block';

            if (ans1 === 'safe' && ans2 === 'risk') {
                resultBox.innerHTML = '<strong>⚠️ [일관성 페널티 발동]</strong><br>손실 거부 성향과 위험 상품 선호 성향 간의 심각한 모순이 감지되었습니다. 알고리즘 내부의 <strong>최소치 지배 규칙(Min-Weighting Rule)</strong>에 의해 사용자의 공격성 선택은 무효화되며, 자산을 보호하기 위해 포트폴리오가 <strong>[안정추구형]</strong>으로 강제 자동 하향 배정됩니다.';
            } else if (ans1 === 'risk' && ans2 === 'safe') {
                resultBox.innerHTML = '<strong>⚠️ [일관성 페널티 발동]</strong><br>높은 변동성 수용 의사에 반해 극도로 안전한 상품만을 조합하는 불일치가 확인되었습니다. 엔진이 신뢰도를 조정하여 포트폴리오 비중을 위험중립 수준의 균등형 자산배분으로 완충 제어합니다.';
            } else if (ans1 === 'safe' && ans2 === 'safe') {
                resultBox.innerHTML = '<strong>진단 완료: [안정추구형 (Conservative)]</strong><br>응답의 논리적 일관성이 매우 높습니다. 알고리즘은 원금 보존에 초점을 맞추어 단기 채권 및 머니마켓펀드(MMF) 위주로 안전망을 극대화합니다.';
            } else {
                resultBox.innerHTML = '<strong>진단 완료: [공격투자형 (Aggressive)]</strong><br>적극적으로 위험을 감수하겠다는 의지가 일관되게 확인되었습니다. 장기 복리 시너지를 위해 글로벌 주식 지수 및 원자재 등 변동성이 높은 성장성 자산 위주로 포트폴리오를 채웁니다.';
            }
        }

customCss:
.single-summary-card-container {
            font-family: 'Noto Sans KR', sans-serif;
            display: flex;
            justify-content: center;
            align-items: center;
            padding: 20px 10px;
            background-color: #e8edf3;
            margin: 20px 0;
        }
        .single-summary-card {
            width: 100%;
            max-width: 700px;
            background-color: #ffffff;
            border-radius: 12px;
            box-shadow: 0 6px 18px rgba(0,0,0,0.1);
            padding: 25px;
            display: flex;
            flex-direction: column;
            overflow: hidden;
            border: 1px solid #cfd8dc;
            box-sizing: border-box;
            height: auto;
        }
        .single-summary-card .card-header {
            display: flex;
            align-items: center;
            border-bottom: 2px solid #4a6572;
            padding-bottom: 12px;
            margin-bottom: 12px;
        }
        .single-summary-card .card-header-icon {
            font-size: 34px;
            color: #4a6572;
            margin-right: 14px;
        }
        .single-summary-card .card-header h3 {
            font-size: 24px;
            color: #263238;
            margin: 0;
            line-height: 1.3;
            font-weight: 700;
        }
        .single-summary-card .card-content {
            flex-grow: 1;
            display: flex;
            flex-direction: column;
            justify-content: space-around;
            font-size: 16px;
            line-height: 1.65;
            color: #333;
        }
        .single-summary-card .card-content .section {
            margin-bottom: 10px;
        }
        .single-summary-card .card-content strong {
            color: #263238;
            font-weight: 600;
        }
        .single-summary-card .card-content .highlight {
            background-color: #e8edf3;
            padding: 2px 6px;
            border-radius: 3px;
            font-weight: bold;
            color: #1a73e8;
        }
        .single-summary-card .card-content .formula {
            background-color: #f4f6f9;
            padding: 8px 12px;
            border-radius: 4px;
            font-size: 0.95em;
            text-align: center;
            margin-top: 5px;
            color: #263238;
            border: 1px dashed #cfd8dc;
        }
        .single-summary-card .card-footer {
            font-size: 14px;
            color: #777;
            text-align: center;
            padding-top: 12px;
            border-top: 1px dashed #cfd8dc;
            margin-top: auto;
        }
        @media (max-width: 768px) {
            .single-summary-card { padding: 18px; height: auto; min-height: unset; }
            .single-summary-card .card-header-icon { font-size: 28px; margin-right: 10px; }
            .single-summary-card .card-header h3 { font-size: 20px; }
            .single-summary-card .card-content { font-size: 15px; line-height: 1.5; }
            .single-summary-card .card-content .section { margin-bottom: 8px; }
            .single-summary-card .card-content .formula { padding: 5px 8px; font-size: 0.85em; }
            .single-summary-card .card-footer { font-size: 13px; padding-top: 10px; }
        }
        @media (max-width: 480px) {
            .single-summary-card { padding: 15px; }
            .single-summary-card .card-header-icon { font-size: 26px; }
            .single-summary-card .card-header h3 { font-size: 18px; }
            .single-summary-card .card-content { font-size: 14px; line-height: 1.4; }
            .single-summary-card .card-content .section { margin-bottom: 6px; }
            .single-summary-card .card-content .formula { padding: 4px 6px; font-size: 0.8em; }
            .single-summary-card .card-footer { font-size: 12px; padding-top: 8px; }
        }

